import { X, FileText, Download, Copy, Sparkles, Check, Plus, Trash2, Building2, MapPin, Calendar } from 'lucide-react';

interface Props {
  isOpen: boolean;
  onClose: () => void;
  project: Project | null;
}

const SourceOfTruthModal: React.FC<Props> = ({ isOpen, onClose, project }) => {
  const [activeTab, setActiveTab] = useState<'edit' | 'preview'>('edit');
  const [format, setFormat] = useState<'txt' | 'json'>('txt');
  const [copied, setCopied] = useState(false);
