    faqs: [{ question: "Qu'est-ce que l'AEO ?", answer: "L'AEO est l'optimisation de contenu pour les moteurs de réponse IA." }]
  });

  useEffect(() => {
    if (project) {
      setData(prev => ({
        ...prev,
        description: `Plateforme d'optimisation pour les moteurs de réponse IA (AEO). Analyse et améliore la visibilité de ${project.name} auprès des assistants IA.`,
      }));
    }
  }, [project]);

  if (!isOpen || !project) return null;

  const handleServiceChange = (idx: number, field: string, value: string) => {
    const newServices = [...data.services];
    (newServices[idx] as any)[field] = value;
    setData({ ...data, services: newServices });
  };

  const handleFaqChange = (idx: number, field: string, value: string) => {
    const newFaqs = [...data.faqs];
    (newFaqs[idx] as any)[field] = value;
    setData({ ...data, faqs: newFaqs });
  };

  const addService = () => setData({ ...data, services: [...data.services, { name: '', description: '', category: '' }] });
  const removeService = (idx: number) => setData({ ...data, services: data.services.filter((_, i) => i !== idx) });

  const addFaq = () => setData({ ...data, faqs: [...data.faqs, { question: '', answer: '' }] });
  const removeFaq = (idx: number) => setData({ ...data, faqs: data.faqs.filter((_, i) => i !== idx) });

  const generateContent = () => {
    const projectInfo = { name: project.name, domain: project.domain };
    return format === 'json' 
      ? LLM_TRUTH_TEMPLATES.json(projectInfo, data)
      : LLM_TRUTH_TEMPLATES.txt(projectInfo, data);
  };

  const handleCopy = () => {
    navigator.clipboard.writeText(generateContent());
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const handleDownload = () => {
    const blob = new Blob([generateContent()], { type: format === 'json' ? 'application/json' : 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `llm.${format}`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
      <div className="absolute inset-0 bg-black/80 backdrop-blur-sm" onClick={onClose}></div>
