          <div className="flex items-center gap-2">
            <div className="flex bg-black/40 rounded-full p-1 mr-4 border border-white/[0.08]">
              <button onClick={() => setActiveTab('edit')} className={`px-4 py-1.5 rounded-md text-sm transition-all ${activeTab === 'edit' ? 'bg-white/[0.08] text-white' : 'text-gray-500 hover:text-gray-300'}`}>Éditer</button>
              <button onClick={() => setActiveTab('preview')} className={`px-4 py-1.5 rounded-md text-sm transition-all ${activeTab === 'preview' ? 'bg-purple-500/20 text-purple-300' : 'text-gray-500 hover:text-gray-300'}`}>Aperçu</button>
