                    <button onClick={() => removeService(idx)} className="absolute top-4 right-4 text-gray-600 hover:text-red-400 opacity-0 group-hover:opacity-100 transition-opacity"><Trash2 size={16} /></button>
                    <div className="grid grid-cols-2 gap-4 mb-3">
                      <input 
                        placeholder="Nom du service"
