                      />
                    </div>
                    <textarea 
                      placeholder="Description factuelle..."
                      value={service.description}
                      onChange={(e) => handleServiceChange(idx, 'description', e.target.value)}
                      className="w-full bg-black/40 border border-white/[0.08] rounded p-2 text-sm text-white h-16"
                    />
                  </div>
                ))}
              </section>

              {/* FAQ Section */}
              <section className="space-y-4 pt-6 border-t border-white/[0.06]">
                <div className="flex justify-between items-center">
                  <h4 className="text-sm font-bold text-purple-400 uppercase tracking-wider flex items-center gap-2">
                    <FileText size={16} /> FAQ (Knowledge Graph)
