                    />
                    <textarea 
                      placeholder="Réponse..."
                      value={faq.answer}
                      onChange={(e) => handleFaqChange(idx, 'answer', e.target.value)}
                      className="w-full bg-black/40 border border-white/[0.08] rounded p-2 text-sm text-gray-300 h-16"
                    />
                  </div>
