              <div className="p-4 border-b border-white/[0.08] flex items-center justify-between bg-[#111111]">
                <div className="flex items-center gap-4">
                  <button onClick={() => setFormat('txt')} className={`text-xs font-bold px-3 py-1 rounded transition-colors ${format === 'txt' ? 'bg-purple-500 text-white' : 'text-gray-500 hover:text-white'}`}>llm.txt</button>
                  <button onClick={() => setFormat('json')} className={`text-xs font-bold px-3 py-1 rounded transition-colors ${format === 'json' ? 'bg-purple-500 text-white' : 'text-gray-500 hover:text-white'}`}>llm.json</button>
                </div>
                <div className="flex gap-2">
                  <button onClick={handleCopy} className="flex items-center gap-2 px-3 py-1.5 bg-white/[0.04] hover:bg-purple-500/10 rounded text-xs font-medium text-white border border-white/[0.08]">
                    {copied ? <Check size={14} className="text-purple-300" /> : <Copy size={14} />}
                    {copied ? 'Copié' : 'Copier'}
