const CodePreview: React.FC<{ code: string; language: string; title: string }> = ({ code, language, title }) => {
  const [copied, setCopied] = useState(false);

  const handleCopy = () => {
    navigator.clipboard.writeText(code);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const handleDownload = () => {
    const ext = language === 'xml' ? 'xml' : language === 'json' ? 'json' : 'html';
    const mime = language === 'xml' ? 'application/xml' : language === 'json' ? 'application/json' : 'text/html';
    const blob = new Blob([code], { type: mime });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = title.toLowerCase().replace(/\s+/g, '-') + '.' + ext;
    a.click();
    URL.revokeObjectURL(url);
  };

  return (
