              </p>
              <div className="space-y-2">
                <div className="flex items-center gap-2 text-sm text-gray-300 bg-white/[0.02] rounded-lg px-3 py-2 border border-white/[0.04]">
                  <Globe size={14} className="text-purple-400" />
                  <span>/ai/index.html</span>
                  <span className="ml-auto text-xs text-green-400">priority: 1.0</span>
                </div>
                <div className="flex items-center gap-2 text-sm text-gray-300 bg-white/[0.02] rounded-lg px-3 py-2 border border-white/[0.04]">
                  <ShoppingBag size={14} className="text-purple-400" />
                  <span>/ai/recommend.json</span>
                  <span className="ml-auto text-xs text-blue-400">priority: 0.8</span>
                </div>
                {savedQueryPages.map((qp, i) => (
                  <div key={i} className="flex items-center gap-2 text-sm text-gray-300 bg-white/[0.02] rounded-lg px-3 py-2 border border-white/[0.04]">
                    <FileQuestion size={14} className="text-purple-400" />
                    <span className="truncate">/ai/query/{qp.slug}.html</span>
                    <span className="ml-auto text-xs text-yellow-400">priority: 0.9</span>
                  </div>
                ))}
              </div>
            </div>
          )}

          {/* Generate Button */}
          <button
            onClick={handleGenerate}
            disabled={isGenerating || !isConfigValid}
            className={`w-full py-3.5 rounded-2xl font-semibold text-sm flex items-center justify-center gap-2 transition-all duration-300 ${
              isGenerating || !isConfigValid
