              </div>
              <h3 className="text-lg font-bold text-gray-300 mb-2">{TABS.find(t => t.id === activeTab)?.label}</h3>
              <p className="text-sm text-gray-500 max-w-sm">
                Configurez les paramètres à gauche puis cliquez sur "Générer" pour créer votre {TABS.find(t => t.id === activeTab)?.desc}
              </p>
            </div>
          )}

          {isGenerating && (
            <div className="ninja-card p-12 flex flex-col items-center justify-center text-center">
              <Loader2 size={40} className="text-purple-400 animate-spin mb-4" />
              <h3 className="text-lg font-bold text-gray-300 mb-2">Génération en cours...</h3>
              <p className="text-sm text-gray-500">Notre IA structure votre contenu pour les moteurs de réponse</p>
            </div>
          )}

          {/* Hub Result */}
          {hubResult && activeTab === 'hub' && !isGenerating && (
            <div className="space-y-4">
              <div className="flex items-center gap-2 mb-2">
                <Check size={16} className="text-emerald-400" />
                <span className="text-sm font-semibold text-emerald-300">Hub Central généré</span>
                <button
                  onClick={() => handlePreview(hubResult.html)}
                  className="ml-auto flex items-center gap-1.5 text-xs text-purple-400 hover:text-purple-300 transition-colors px-3 py-1.5 rounded-lg hover:bg-white/[0.04]"
                >
                  <Eye size={12} /> Aperçu
                </button>
              </div>
              <CodePreview code={hubResult.html} language="html" title="ai/index.html" />
            </div>
          )}

          {/* Query Result */}
          {queryResult && activeTab === 'query' && !isGenerating && (
            <div className="space-y-4">
              <div className="flex items-center gap-2 mb-2">
                <Check size={16} className="text-emerald-400" />
                <span className="text-sm font-semibold text-emerald-300">Query Page générée</span>
                <button
                  onClick={() => handlePreview(queryResult.html)}
                  className="ml-auto flex items-center gap-1.5 text-xs text-purple-400 hover:text-purple-300 transition-colors px-3 py-1.5 rounded-lg hover:bg-white/[0.04]"
                >
                  <Eye size={12} /> Aperçu
                </button>
              </div>
              <div className="ninja-card p-3">
                <div className="flex items-center gap-2 text-xs text-gray-400">
                  <FileText size={12} />
                  <span>Slug: <code className="text-purple-300">/ai/query/{queryResult.slug}.html</code></span>
                </div>
              </div>
              <CodePreview code={queryResult.html} language="html" title={`ai/query/${queryResult.slug}.html`} />
            </div>
          )}

          {/* Recommend Result */}
          {recommendResult && activeTab === 'recommend' && !isGenerating && (
            <div className="space-y-4">
              <div className="flex items-center gap-2 mb-2">
                <Check size={16} className="text-emerald-400" />
                <span className="text-sm font-semibold text-emerald-300">{recommendResult.productCount} produit{recommendResult.productCount > 1 ? 's' : ''} catalogué{recommendResult.productCount > 1 ? 's' : ''}</span>
              </div>
              <CodePreview code={recommendResult.json} language="json" title="ai/recommend.json" />
            </div>
          )}

          {/* Sitemap Result */}
          {sitemapResult && activeTab === 'sitemap' && !isGenerating && (
            <div className="space-y-4">
              <div className="flex items-center gap-2 mb-2">
                <Check size={16} className="text-emerald-400" />
                <span className="text-sm font-semibold text-emerald-300">{sitemapResult.urlCount} URL{sitemapResult.urlCount > 1 ? 's' : ''} indexée{sitemapResult.urlCount > 1 ? 's' : ''}</span>
              </div>
              <CodePreview code={sitemapResult.xml} language="xml" title="sitemap-ai.xml" />
            </div>
          )}
        </div>
      </div>

      {/* Preview Modal */}
      {showPreview && (
        <div className="fixed inset-0 z-[100] bg-black/80 backdrop-blur-sm flex items-center justify-center p-4">
          <div className="bg-[#13131d] border border-white/[0.08] rounded-2xl w-full max-w-5xl h-[80vh] flex flex-col overflow-hidden">
            <div className="flex items-center justify-between px-4 py-3 border-b border-white/[0.06]">
              <span className="text-sm font-semibold text-gray-300 flex items-center gap-2">
                <Eye size={14} className="text-purple-400" /> Aperçu de la page
              </span>
              <button
                onClick={() => setShowPreview(false)}
                className="text-gray-400 hover:text-white transition-colors p-1"
              >
                ✕
              </button>
            </div>
            <iframe
              ref={iframeRef}
              className="flex-1 w-full bg-white"
              title="Preview"
              sandbox=""
              srcDoc={previewHtml}
            />
          </div>
        </div>
      )}
    </div>
  );
};

export default AiResponseLayer;

